def search_hadith(query, topn=10):
    nq = normalize_arabic(query)
    res=[]
    for rec in hadith_db:
        text = rec.get('hadithTxt') or rec.get('Matn') or ''
        b = normalize_arabic(text)
        if not b:
            continue
        if nq in b:
            score=1.0
        else:
            score=lcs_ratio(nq,b)
        tf1 = token_f1(query, text)
        comb = max(score, tf1)
        if comb > 0.6:
            res.append((comb, score, tf1, rec))
    res.sort(key=lambda x: x[0], reverse=True)
    return res[:topn]
